// Parse JSON health report and check status
const sshOutput = $input.first().json;
const jsonStr = sshOutput.stdout || '{}';

try {
  const report = JSON.parse(jsonStr);
  const overallStatus = report.overall_status || 'unknown';

  // Parse timestamp and check freshness (within 26 hours)
  const reportTime = new Date(report.timestamp.replace(/_/g, '-').replace(/-/g, '-').substring(0, 19));
  const now = new Date();
  const ageHours = (now - reportTime) / (1000 * 60 * 60);
  const isStale = ageHours > 26;

  return {
    json: {
      overallStatus: overallStatus,
      reportTimestamp: report.timestamp,
      ageHours: Math.round(ageHours * 10) / 10,
      isStale: isStale,
      hasFailed: (overallStatus !== 'pass' || isStale),
      checks: report.checks
    }
  };
} catch (error) {
  return {
    json: {
      overallStatus: 'error',
      hasFailed: true,
      error: error.message
    }
  };
}

const sshOutput = $input.first().json;
const stdout = sshOutput.stdout || '';
const stderr = sshOutput.stderr || '';
const exitCode = sshOutput.code || 0;

const timestamp = new Date().toLocaleString('en-US', { 
  timeZone: 'America/Chicago',
  hour12: true
});

const html = `<h2>❌ Backup Verification Failed</h2>
<p><strong>Time:</strong> ${timestamp}</p>
<p><strong>Exit Code:</strong> ${exitCode}</p>
<p><strong>Output:</strong></p>
<pre style="background: #f5f5f5; padding: 10px; border: 1px solid #ddd;">${stdout}</pre>
${stderr ? `<p><strong>Errors:</strong></p><pre style="background: #fff3cd; padding: 10px; border: 1px solid #ffc107;">${stderr}</pre>` : ''}`;

return {
  json: {
    emailSubject: '❌ Backup Verification Failed - ' + timestamp,
    emailBody: html
  }
};
